pub fn stuff(a: &str) -> String {
    fn increment_char(c: char) -> char {
        match c {
            'A'..='Z' => (((c as u8 - 65 + 1) % 26) + 65) as char,
            'a'..='z' => (((c as u8 - 97 + 1) % 26) + 97) as char,
            _ => c,
        }
    }

    fn process_chars(chars: std::iter::Rev<std::str::Chars>) -> Vec<char> {
        chars.map(increment_char).collect()
    }

    fn build_string(chars: Vec<char>) -> String {
        chars.into_iter().fold(String::new(), |mut acc, c| {
            acc.push(c);
            acc
        })
    }

    build_string(process_chars(a.chars().rev()))
}
